// Extrair dados da mensagem do WhatsApp (Evolution API)
const body = $input.first().json.body || $input.first().json;

let phone = '';
let message = '';
let pushName = '';

if (body.data) {
  phone = body.data.key?.remoteJid?.replace('@s.whatsapp.net', '') || '';
  message = body.data.message?.conversation || body.data.message?.extendedTextMessage?.text || '';
  pushName = body.data.pushName || '';
} else {
  phone = body.phone || body.from || '';
  message = body.message || body.text || '';
  pushName = body.pushName || body.name || '';
}

phone = phone.replace(/\D/g, '');
if (!phone.startsWith('55') && (phone.length === 11 || phone.length === 10)) {
  phone = '55' + phone;
}

const hoje = new Date();
const diasSemana = ['domingo', 'segunda-feira', 'terça-feira', 'quarta-feira', 'quinta-feira', 'sexta-feira', 'sábado'];
const meses = ['janeiro', 'fevereiro', 'março', 'abril', 'maio', 'junho', 'julho', 'agosto', 'setembro', 'outubro', 'novembro', 'dezembro'];

const dataAtual = `${diasSemana[hoje.getDay()]}, ${hoje.getDate()} de ${meses[hoje.getMonth()]} de ${hoje.getFullYear()}`;
const dataISO = hoje.toISOString().split('T')[0];

return { phone, message, pushName, dataAtual, dataISO, timestamp: new Date().toISOString() };

const SUPABASE_URL = 'https://yqrjbyaucimvmzpfipgs.supabase.co';
const SUPABASE_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InlxcmpieWF1Y2ltdm16cGZpcGdzIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3NTc3MTQ4NywiZXhwIjoyMDkxMzQ3NDg3fQ.q4VwAwLbPQTXGCdW1ZfLvmyW8TAQuJ67LgI3gCO6mzg';
const CLINIC_ID = '6a718c1d-9a79-4e80-ad71-1c5c8a2ea190';

const phone = $input.first().json.phone;
const pushName = $input.first().json.pushName;
const message = $input.first().json.message;
const dataAtual = $input.first().json.dataAtual;

let conversationHistory = [];
let leadId = null;
let patientId = null;
let customerName = pushName || '';

try {
  const convResponse = await fetch(
    `${SUPABASE_URL}/rest/v1/eva_conversations?phone=eq.${phone}&clinic_id=eq.${CLINIC_ID}&select=*`,
    { headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}` } }
  );
  const conversations = await convResponse.json();

  if (conversations && conversations.length > 0) {
    const conv = conversations[0];
    conversationHistory = conv.messages || [];
    leadId = conv.lead_id;
    patientId = conv.patient_id;
    customerName = conv.customer_name || pushName || '';
  }

  if (!leadId) {
    const leadResponse = await fetch(
      `${SUPABASE_URL}/rest/v1/leads?phone=eq.${phone}&clinic_id=eq.${CLINIC_ID}&select=id,name,stage`,
      { headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}` } }
    );
    const leads = await leadResponse.json();
    if (leads && leads.length > 0) {
      leadId = leads[0].id;
      if (leads[0].name && leads[0].name !== 'Lead WhatsApp') customerName = leads[0].name;
    }
  }

  if (!patientId) {
    const patientResponse = await fetch(
      `${SUPABASE_URL}/rest/v1/patients?phone=eq.${phone}&clinic_id=eq.${CLINIC_ID}&select=id,name`,
      { headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}` } }
    );
    const patients = await patientResponse.json();
    if (patients && patients.length > 0) {
      patientId = patients[0].id;
      customerName = patients[0].name || customerName;
    }
  }
} catch (e) { console.error('Erro ao buscar histórico:', e); }

const recentHistory = conversationHistory.slice(-20);
let historyText = '';
if (recentHistory.length > 0) {
  historyText = '\n\nHISTÓRICO DA CONVERSA:\n';
  for (const msg of recentHistory) {
    const role = msg.role === 'user' ? 'Paciente' : 'Donna';
    historyText += `${role}: ${msg.content}\n`;
  }
}

conversationHistory.push({ role: 'user', content: message, timestamp: new Date().toISOString() });

return {
  phone, message, pushName, dataAtual,
  dataISO: $input.first().json.dataISO,
  customerName, conversationHistory, historyText,
  leadId, patientId, clinicId: CLINIC_ID,
  isNewConversation: recentHistory.length === 0
};

