function parseData(input) {
  const hoje = new Date();
  const ano = hoje.getFullYear();
  const mes = hoje.getMonth();
  const dia = hoje.getDate();
  const texto = String(input).toLowerCase().trim();

  if (texto === 'hoje') return hoje;
  if (texto === 'amanhã' || texto === 'amanha') return new Date(ano, mes, dia + 1);

  const diasSemana = { 'domingo': 0, 'segunda': 1, 'terca': 2, 'terça': 2, 'quarta': 3, 'quinta': 4, 'sexta': 5, 'sabado': 6, 'sábado': 6 };
  for (const [nome, diaSem] of Object.entries(diasSemana)) {
    if (texto.includes(nome)) {
      const d = new Date(ano, mes, dia);
      const diff = (diaSem - d.getDay() + 7) % 7 || 7;
      d.setDate(d.getDate() + diff);
      return d;
    }
  }

  const matchBarra = texto.match(/(\d{1,2})\/(\d{1,2})(?:\/(\d{2,4}))?/);
  if (matchBarra) {
    let [_, d, m, a] = matchBarra;
    a = a ? (a.length === 2 ? '20' + a : a) : ano;
    return new Date(parseInt(a), parseInt(m) - 1, parseInt(d));
  }

  const matchISO = texto.match(/(\d{4})-(\d{2})-(\d{2})/);
  if (matchISO) {
    const [_, a, m, d] = matchISO;
    return new Date(parseInt(a), parseInt(m) - 1, parseInt(d));
  }

  const matchDia = texto.match(/(?:dia\s+)?(\d{1,2})/);
  if (matchDia) return new Date(ano, mes, parseInt(matchDia[1]));

  return null;
}

